[package]
name = "os"
version = "0.1.0"
authors = ["Kairix"]
edition = "2024"

# See more keys and their definitions at https://doc.rust-lang.org/cargo/reference/manifest.html

[dependencies]


lazy_static = { version = "1.5.0", features = ["spin_no_std"] }
buddy_system_allocator = "0.11.0"
bitflags = "2.11.0"
xmas-elf = "0.10.0"
virtio-drivers = { version = "0.7" }
lwext4_rust = { path = "../lwext4_rust" }
fatfs = { path = "vendor/fatfs", default-features = false, features = [
# fatfs = { git = "https://github.com/rafalh/rust-fatfs", branch = "master", default-features = false, features = [
    "alloc",
    "lfn",
    "unicode",
] }
log = "0.4"
spin = { version = "0.9", default-features = false, features = [
    "mutex",
    "rwlock",
] }
flat_device_tree = "3.1.1"

polyhal = { path = "../polyhal/polyhal", features = [
    "trap",
    "boot",
], default-features = false }
polyhal-trap = { path = "../polyhal/polyhal-trap", default-features = false }
polyhal-boot = { path = "../polyhal/polyhal-boot", default-features = false }
# cty = { git = "https://github.com/rust-lang/cty", branch = "master" }


[target.'cfg(target_arch = "riscv64")'.dependencies]
riscv = { path = "vendor/riscv-0.6.0", features = ["inline-asm"] }
# riscv = { git = "https://github.com/rcore-os/riscv", features = ["inline-asm"] }
sbi-rt = { version = "0.0.3", features = ["legacy"] }
[target.'cfg(target_arch = "loongarch64")'.dependencies]
loongArch64 = "0.2.4"

# [target.'cfg(target_arch = "loongarch64")'.dependencies]
# loongArch64 = "0.2.4"
# ns16550a = "0.5.0"


[profile.release]
debug = true

[patch.crates-io]
polyhal = { path = "../polyhal/polyhal" }
polyhal-trap = { path = "../polyhal/polyhal-trap" }
polyhal-boot = { path = "../polyhal/polyhal-boot" }
cty = { path = "../patches/cty" }

//! The main module and entrypoint
//!
//! Various facilities of the kernels are implemented as submodules. The most
//! important ones are:
//!
//! - [`trap`]: Handles all cases of switching from userspace to the kernel
//! - [`task`]: Task management
//! - [`syscall`]: System call handling and implementation
//! - [`mm`]: Address map using SV39
//! - [`sync`]: Wrap a static data structure inside it so that we are able to access it without any `unsafe`.
//! - [`fs`]: Separate user from file system with some structures
//!
//! The operating system also starts in this module. Kernel code starts
//! executing from `entry.asm`, after which [`rust_main()`] is called to
//! initialize various pieces of functionality. (See its source code for
//! details.)
//!
//! We then call [`task::run_tasks()`] and for the first time go to
//! userspace.

#![deny(missing_docs)]
#![deny(warnings)]
#![allow(unused_imports)]
#![no_std]
#![no_main]
#![feature(alloc_error_handler)]
#![feature(step_trait)]
#![feature(naked_functions)]
#![cfg_attr(target_arch = "riscv64", feature(riscv_ext_intrinsics))]
// #![feature(riscv_ext_intrinsics)]
use core::time::Duration;
extern crate alloc;
// extern crate flat_device_tree;
use alloc::sync::Arc;
use alloc::vec::Vec;

#[macro_use]
extern crate bitflags;
use crate::syscall::signal::handle_signals;
use crate::syscall::signal::sys_rt_sigreturn;
use core::arch::naked_asm;
use log::*;
use mm::vm_set;
use polyhal::VirtAddr;
use polyhal::consts::VIRT_ADDR_START;
use polyhal::utils::addr::PhysPageNum;
use trap::_set_sum_bit;
use trap::handle_page_fault;
#[path = "boards/qemu.rs"]
mod board;
use crate::mm::vm_set::VMSpace;
use crate::timer::set_next_trigger;
use crate::vm_set::PageFaultError;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
// #[macro_use]
// mod console;
pub use polyhal::println;
#[allow(missing_docs)]
pub mod arch;
mod config;
#[allow(missing_docs)]
pub mod devices;
mod drivers;
mod embedded;
/// error code
pub mod error;
///
pub mod fs;
pub mod lang_items;
mod logging;
pub mod mm;
mod net;
///
#[cfg(target_arch = "riscv64")]
pub mod sbi;
mod socket;

///
#[cfg(target_arch = "loongarch64")]
pub mod sbi_la;

pub mod sync;
pub mod syscall;
#[allow(missing_docs)]
pub mod task;

// #[cfg(target_arch = "riscv64")]
pub mod timer;

#[cfg(target_arch = "riscv64")]
fn trap_from_user(ctx: &polyhal_trap::trapframe::TrapFrame) -> bool {
    ctx.from_user()
}

#[cfg(target_arch = "loongarch64")]
fn trap_from_user(ctx: &polyhal_trap::trapframe::TrapFrame) -> bool {
    ctx.prmd & 0b11 == 0b11
}
pub mod trap;
use crate::task::init_processors;
